import React, { useRef, useEffect, useState, useCallback } from 'react';
import { useDesignTokens } from '../context/DesignTokenContext';
import { SmartParserPreview } from './SmartParser';
import type { SectionSchema } from '../types/sections';

// ============================================================
// RESUME CANVAS — CSS-scaled <div> that mirrors final PDF
// ============================================================
// Fixed at 816×1056px (8.5" × 11" at 96 DPI). A ResizeObserver
// measures the container and computes a scale factor so the
// page always fits. All content uses semantic HTML (h1, h2, p,
// span, ul/li) for ATS compatibility — zero tables.
// ============================================================

const PAGE_W = 816;  // 8.5in * 96dpi
const PAGE_H = 1056; // 11in * 96dpi

// ---- Per-section renderer ----

const SectionRenderer = React.memo(function SectionRenderer({
  section,
}: {
  section: SectionSchema;
}) {
  if (!section.visible) return null;

  const getField = (key: string) =>
    section.fields.find((f) => f.key === key)?.value ?? '';

  switch (section.type) {
    // ---- STANDARD: Experience / Education ----
    case 'experience':
    case 'education':
      return (
        <section aria-label={section.title} style={{ marginBottom: 'var(--r-section-gap)' }}>
          <h2 style={h2Style}>{section.title}</h2>
          <hr style={hrStyle} />
          <div style={{ marginBottom: 'var(--r-item-gap)' }}>
            {getField('title') && (
              <h3 style={h3Style}>{getField('title') || getField('degree')}</h3>
            )}
            {getField('degree') && !getField('title') && (
              <h3 style={h3Style}>{getField('degree')}</h3>
            )}
            <p style={metaStyle}>
              {getField('company') || getField('school')}
              {(getField('company') || getField('school')) && getField('dates') && ' | '}
              {getField('dates') && <span>{getField('dates')}</span>}
            </p>
          </div>
          <SmartParserPreview value={getField('bullets') || getField('details')} />
        </section>
      );

    // ---- STANDARD: Skills ----
    case 'skills':
      return (
        <section aria-label={section.title} style={{ marginBottom: 'var(--r-section-gap)' }}>
          <h2 style={h2Style}>{section.title}</h2>
          <hr style={hrStyle} />
          <SmartParserPreview value={getField('skills')} bulletIcon="fa-check" />
        </section>
      );

    // ---- ENHANCV: Philosophy ----
    case 'philosophy':
      return (
        <section aria-label={section.title} style={{ marginBottom: 'var(--r-section-gap)' }}>
          <h2 style={h2Style}>{section.title}</h2>
          <hr style={hrStyle} />
          <p style={{
            fontStyle: 'italic',
            lineHeight: 'var(--r-line-height)',
            color: '#374151',
            borderLeft: '3px solid var(--r-accent)',
            paddingLeft: '12px',
            margin: 0,
          }}>
            {getField('quote')}
          </p>
        </section>
      );

    // ---- ENHANCV: Tech Stack Icons ----
    case 'tech-stack': {
      const techs = getField('icons')
        .split(',')
        .map((t) => t.trim())
        .filter(Boolean);
      return (
        <section aria-label={section.title} style={{ marginBottom: 'var(--r-section-gap)' }}>
          <h2 style={h2Style}>{section.title}</h2>
          <hr style={hrStyle} />
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
            {techs.map((tech, i) => (
              <span
                key={i}
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '4px',
                  padding: '4px 10px',
                  borderRadius: '6px',
                  fontSize: '11px',
                  fontWeight: 500,
                  background: 'var(--r-accent-light)',
                  color: 'var(--r-accent)',
                  border: '1px solid var(--r-accent-muted)',
                }}
              >
                <i className="fa-solid fa-microchip" style={{ fontSize: '9px' }} />
                {tech}
              </span>
            ))}
          </div>
        </section>
      );
    }

    // ---- ENHANCV: Skills Cloud ----
    case 'skills-cloud': {
      const tags = getField('tags')
        .split(',')
        .map((t) => t.trim())
        .filter(Boolean);
      // Simple weighted cloud: larger font for earlier entries
      return (
        <section aria-label={section.title} style={{ marginBottom: 'var(--r-section-gap)' }}>
          <h2 style={h2Style}>{section.title}</h2>
          <hr style={hrStyle} />
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px', alignItems: 'baseline' }}>
            {tags.map((tag, i) => {
              const size = Math.max(11, 18 - i * 1.5);
              const opacity = Math.max(0.5, 1 - i * 0.08);
              return (
                <span
                  key={i}
                  style={{
                    fontSize: `${size}px`,
                    fontWeight: i < 3 ? 600 : 400,
                    color: 'var(--r-accent)',
                    opacity,
                  }}
                >
                  {tag}
                </span>
              );
            })}
          </div>
        </section>
      );
    }

    // ---- ENHANCV: Strengths ----
    case 'strengths':
      return (
        <section aria-label={section.title} style={{ marginBottom: 'var(--r-section-gap)' }}>
          <h2 style={h2Style}>{section.title}</h2>
          <hr style={hrStyle} />
          <SmartParserPreview value={getField('strengths')} bulletIcon="fa-star" />
        </section>
      );

    // ---- Custom ----
    case 'custom':
      return (
        <section aria-label={section.title} style={{ marginBottom: 'var(--r-section-gap)' }}>
          <h2 style={h2Style}>{section.title}</h2>
          <hr style={hrStyle} />
          <SmartParserPreview value={getField('content')} />
        </section>
      );

    default:
      return null;
  }
});

// ---- Shared inline styles (avoid Tailwind inside the PDF canvas) ----

const h2Style: React.CSSProperties = {
  fontSize: '14px',
  fontWeight: 700,
  textTransform: 'uppercase',
  letterSpacing: '0.05em',
  color: 'var(--r-accent)',
  margin: '0 0 2px 0',
  fontFamily: 'inherit',
  lineHeight: 'var(--r-line-height)',
};

const h3Style: React.CSSProperties = {
  fontSize: '13px',
  fontWeight: 600,
  color: '#111827',
  margin: 0,
  lineHeight: 'var(--r-line-height)',
};

const metaStyle: React.CSSProperties = {
  fontSize: '11px',
  color: '#6b7280',
  margin: '0 0 var(--r-item-gap) 0',
  lineHeight: 'var(--r-line-height)',
};

const hrStyle: React.CSSProperties = {
  border: 'none',
  borderTop: '1.5px solid var(--r-accent)',
  margin: '4px 0 var(--r-item-gap) 0',
  opacity: 0.4,
};

// ============================================================
// MAIN CANVAS COMPONENT
// ============================================================

interface ResumeCanvasProps {
  sections: SectionSchema[];
  layout: '1-col' | '2-col';
  applicantName?: string;
  contactLine?: string;
}

export default function ResumeCanvas({
  sections,
  layout,
  applicantName = 'Your Name',
  contactLine = 'city@email.com | (555) 123-4567 | linkedin.com/in/you',
}: ResumeCanvasProps) {
  const { cssVars } = useDesignTokens();
  const containerRef = useRef<HTMLDivElement>(null);
  const [scale, setScale] = useState(1);

  // ---- Responsive scaling ----
  const recalcScale = useCallback(() => {
    if (!containerRef.current) return;
    const containerW = containerRef.current.clientWidth;
    setScale(Math.min(containerW / PAGE_W, 1));
  }, []);

  useEffect(() => {
    recalcScale();
    const ro = new ResizeObserver(recalcScale);
    if (containerRef.current) ro.observe(containerRef.current);
    return () => ro.disconnect();
  }, [recalcScale]);

  // ---- Split sections by column ----
  const visible = sections.filter((s) => s.visible);
  const mainSections = layout === '2-col'
    ? visible.filter((s) => s.column === 'main')
    : visible;
  const sidebarSections = layout === '2-col'
    ? visible.filter((s) => s.column === 'sidebar')
    : [];

  return (
    <div ref={containerRef} className="resume-canvas-container w-full overflow-hidden">
      {/* Scaled page */}
      <div
        className="resume-page"
        style={{
          width: PAGE_W,
          minHeight: PAGE_H,
          transform: `scale(${scale})`,
          transformOrigin: 'top left',
          background: '#ffffff',
          boxShadow: '0 4px 24px rgba(0,0,0,0.12)',
          borderRadius: '2px',
          padding: '48px',
          fontFamily: 'var(--r-font-family)',
          fontSize: '12px',
          lineHeight: 'var(--r-line-height)',
          color: '#1f2937',
          boxSizing: 'border-box',
          // Spread design-token CSS vars onto the page root
          ...cssVars,
        } as React.CSSProperties}
      >
        {/* ---- Header (always semantic) ---- */}
        <header style={{ textAlign: 'center', marginBottom: 'var(--r-section-gap)' }}>
          <h1
            style={{
              fontSize: '24px',
              fontWeight: 700,
              margin: '0 0 4px 0',
              color: '#111827',
              letterSpacing: '0.02em',
              lineHeight: 1.2,
            }}
          >
            {applicantName}
          </h1>
          <p style={{ fontSize: '11px', color: '#6b7280', margin: 0 }}>{contactLine}</p>
        </header>

        {/* ---- Body ---- */}
        {layout === '1-col' ? (
          <div>
            {mainSections.map((sec) => (
              <SectionRenderer key={sec.id} section={sec} />
            ))}
          </div>
        ) : (
          <div style={{ display: 'flex', gap: '32px' }}>
            {/* Main column — 65% */}
            <div style={{ flex: '0 0 65%' }}>
              {mainSections.map((sec) => (
                <SectionRenderer key={sec.id} section={sec} />
              ))}
            </div>
            {/* Sidebar — 35% */}
            <div
              style={{
                flex: '0 0 calc(35% - 32px)',
                borderLeft: '1px solid #e5e7eb',
                paddingLeft: '20px',
              }}
            >
              {sidebarSections.map((sec) => (
                <SectionRenderer key={sec.id} section={sec} />
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Reserve container space for the scaled page */}
      <div style={{ height: PAGE_H * scale, pointerEvents: 'none' }} />
    </div>
  );
}
