import { useState, useCallback } from 'react';
import type {
  SectionSchema,
  SectionType,
  ColumnSlot,
} from '../types/sections';
import { SECTION_BLUEPRINTS } from '../types/sections';

// ============================================================
// useSectionManager — CRUD + reorder for resume sections
// ============================================================
// This hook owns the array of SectionSchema objects. It exposes
// atomic operations so the editor never needs to manipulate the
// array directly. DnD reorder, column toggling, field updates,
// and layout switching all funnel through here.
// ============================================================

export type LayoutMode = '1-col' | '2-col';

export interface SectionManagerAPI {
  sections: SectionSchema[];
  layout: LayoutMode;

  // CRUD
  addSection: (type: SectionType) => void;
  addCustomSection: (title: string) => void;
  removeSection: (id: string) => void;
  duplicateSection: (id: string) => void;
  toggleVisibility: (id: string) => void;

  // Field updates
  updateField: (sectionId: string, fieldKey: string, value: string) => void;
  updateTitle: (sectionId: string, title: string) => void;

  // Reorder (drag-and-drop)
  reorder: (fromIndex: number, toIndex: number) => void;
  moveToColumn: (id: string, column: ColumnSlot) => void;

  // Layout
  setLayout: (mode: LayoutMode) => void;

  // Bulk
  loadSections: (sections: SectionSchema[]) => void;
}

let _counter = 0;
const uid = () => `sec_${Date.now()}_${++_counter}`;

export function useSectionManager(
  initialSections: SectionSchema[] = [],
  initialLayout: LayoutMode = '1-col',
): SectionManagerAPI {
  const [sections, setSections] = useState<SectionSchema[]>(initialSections);
  const [layout, setLayout] = useState<LayoutMode>(initialLayout);

  // ---- CRUD ----

  const addSection = useCallback((type: SectionType) => {
    if (type === 'custom') return; // use addCustomSection instead
    const blueprint = SECTION_BLUEPRINTS[type];
    if (!blueprint) return;
    setSections((prev) => {
      const newSection = blueprint();
      newSection.order = prev.length;
      return [...prev, newSection];
    });
  }, []);

  const addCustomSection = useCallback((title: string) => {
    setSections((prev) => [
      ...prev,
      {
        id: uid(),
        type: 'custom' as const,
        category: 'custom' as const,
        title,
        icon: 'fa-pen-nib',
        column: 'main' as ColumnSlot,
        order: prev.length,
        visible: true,
        fields: [
          {
            key: 'content',
            label: 'Content',
            type: 'bullet-text' as const,
            placeholder: '- Add your content here',
            value: '',
          },
        ],
      },
    ]);
  }, []);

  const removeSection = useCallback((id: string) => {
    setSections((prev) => prev.filter((s) => s.id !== id));
  }, []);

  const duplicateSection = useCallback((id: string) => {
    setSections((prev) => {
      const source = prev.find((s) => s.id === id);
      if (!source) return prev;
      const clone: SectionSchema = {
        ...source,
        id: uid(),
        title: `${source.title} (Copy)`,
        order: prev.length,
        fields: source.fields.map((f) => ({ ...f })),
      };
      const idx = prev.findIndex((s) => s.id === id);
      const next = [...prev];
      next.splice(idx + 1, 0, clone);
      return next;
    });
  }, []);

  const toggleVisibility = useCallback((id: string) => {
    setSections((prev) =>
      prev.map((s) => (s.id === id ? { ...s, visible: !s.visible } : s)),
    );
  }, []);

  // ---- Field updates ----

  const updateField = useCallback(
    (sectionId: string, fieldKey: string, value: string) => {
      setSections((prev) =>
        prev.map((s) =>
          s.id === sectionId
            ? {
                ...s,
                fields: s.fields.map((f) =>
                  f.key === fieldKey ? { ...f, value } : f,
                ),
              }
            : s,
        ),
      );
    },
    [],
  );

  const updateTitle = useCallback((sectionId: string, title: string) => {
    setSections((prev) =>
      prev.map((s) => (s.id === sectionId ? { ...s, title } : s)),
    );
  }, []);

  // ---- Reorder ----

  const reorder = useCallback((fromIndex: number, toIndex: number) => {
    setSections((prev) => {
      const next = [...prev];
      const [moved] = next.splice(fromIndex, 1);
      next.splice(toIndex, 0, moved);
      return next.map((s, i) => ({ ...s, order: i }));
    });
  }, []);

  const moveToColumn = useCallback((id: string, column: ColumnSlot) => {
    setSections((prev) =>
      prev.map((s) => (s.id === id ? { ...s, column } : s)),
    );
  }, []);

  // ---- Bulk ----

  const loadSections = useCallback((incoming: SectionSchema[]) => {
    setSections(incoming);
  }, []);

  return {
    sections,
    layout,
    addSection,
    addCustomSection,
    removeSection,
    duplicateSection,
    toggleVisibility,
    updateField,
    updateTitle,
    reorder,
    moveToColumn,
    setLayout,
    loadSections,
  };
}
