import React, { useState, useCallback } from 'react';

// ============================================================
// EXPORT BUTTON — html2pdf.js export from the canvas <div>
// ============================================================
// Finds the .resume-page element inside the canvas container,
// clones it at full 816×1056 resolution (no CSS scale), and
// passes it to html2pdf for a pixel-perfect A4 PDF.
//
// html2pdf.js is loaded from CDN (same as the existing app).
// ============================================================

interface ExportButtonProps {
  canvasRef: React.RefObject<HTMLDivElement | null>;
  applicantName: string;
}

declare global {
  interface Window {
    html2pdf: any;
  }
}

export default function ExportButton({ canvasRef, applicantName }: ExportButtonProps) {
  const [exporting, setExporting] = useState(false);

  const handleExport = useCallback(async () => {
    const container = canvasRef.current;
    if (!container) return;

    // Find the actual .resume-page inside the canvas container
    const page = container.querySelector('.resume-page') as HTMLElement | null;
    if (!page) return;

    // Ensure html2pdf is available
    if (!window.html2pdf) {
      // Dynamically load from CDN if not already present
      await new Promise<void>((resolve, reject) => {
        const script = document.createElement('script');
        script.src =
          'https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js';
        script.onload = () => resolve();
        script.onerror = () => reject(new Error('Failed to load PDF library'));
        document.head.appendChild(script);
      });
    }

    setExporting(true);

    try {
      // Clone the page so we can remove the CSS scale for export
      const clone = page.cloneNode(true) as HTMLElement;
      clone.style.transform = 'none';
      clone.style.position = 'absolute';
      clone.style.left = '-9999px';
      clone.style.top = '0';
      document.body.appendChild(clone);

      const safeName = applicantName.replace(/[^a-zA-Z0-9]/g, '_') || 'Resume';
      const date = new Date().toISOString().slice(0, 10);
      const filename = `${safeName}_Resume_${date}.pdf`;

      await window.html2pdf()
        .set({
          margin: 0,
          filename,
          image: { type: 'jpeg', quality: 0.98 },
          html2canvas: {
            scale: 2,
            useCORS: true,
            letterRendering: true,
            width: 816,
            height: 1056,
          },
          jsPDF: {
            unit: 'px',
            format: [816, 1056],
            hotfixes: ['px_scaling'],
          },
          pagebreak: { mode: ['avoid-all'] },
        })
        .from(clone)
        .save();

      document.body.removeChild(clone);
    } catch (err) {
      console.error('PDF export failed:', err);
    } finally {
      setExporting(false);
    }
  }, [canvasRef, applicantName]);

  return (
    <button
      onClick={handleExport}
      disabled={exporting}
      className="btn primary-btn small-btn"
      style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', fontSize: '0.8rem' }}
    >
      {exporting ? (
        <>
          <i className="fa-solid fa-spinner fa-spin" />
          Exporting...
        </>
      ) : (
        <>
          <i className="fa-solid fa-file-pdf" />
          Export PDF
        </>
      )}
    </button>
  );
}
