import { useEffect, useRef, useCallback } from 'react';
import type { SectionSchema, DesignTokens } from '../types/sections';
import type { LayoutMode } from './useSectionManager';

// ============================================================
// usePersistence — auto-save resume state to Supabase + localStorage
// ============================================================
// Strategy:
//   1. localStorage: immediate writes on every change (fast recovery)
//   2. Supabase `resume_drafts` table: debounced writes (cloud sync)
//
// On mount, tries to hydrate from Supabase first (cloud),
// falls back to localStorage (offline / no auth).
// ============================================================

const LS_KEY = 'tms_builder_state';
const DEBOUNCE_MS = 2000; // save to cloud every 2s at most

interface PersistedState {
  sections: SectionSchema[];
  layout: LayoutMode;
  tokens: DesignTokens;
  applicantName: string;
  contactLine: string;
  savedAt: number;
}

// ---- localStorage helpers ----

function saveToLocal(state: PersistedState) {
  try {
    localStorage.setItem(LS_KEY, JSON.stringify(state));
  } catch {
    // localStorage full or unavailable — swallow
  }
}

export function loadFromLocal(): PersistedState | null {
  try {
    const raw = localStorage.getItem(LS_KEY);
    if (!raw) return null;
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

// ---- Supabase helpers ----

async function getSupabase() {
  return window.supabaseClient || null;
}

async function saveToCloud(state: PersistedState) {
  const supabase = await getSupabase();
  if (!supabase) return;

  try {
    const { data: sessionData } = await supabase.auth.getSession();
    const userId = sessionData?.session?.user?.id;
    if (!userId) return; // not logged in — skip cloud save

    await supabase.from('resume_drafts').upsert(
      {
        user_id: userId,
        draft_data: state,
        updated_at: new Date().toISOString(),
      },
      { onConflict: 'user_id' },
    );
  } catch (err) {
    console.warn('Cloud save failed (non-critical):', err);
  }
}

export async function loadFromCloud(): Promise<PersistedState | null> {
  const supabase = await getSupabase();
  if (!supabase) return null;

  try {
    const { data: sessionData } = await supabase.auth.getSession();
    const userId = sessionData?.session?.user?.id;
    if (!userId) return null;

    const { data, error } = await supabase
      .from('resume_drafts')
      .select('draft_data')
      .eq('user_id', userId)
      .single();

    if (error || !data) return null;
    return data.draft_data as PersistedState;
  } catch {
    return null;
  }
}

// ============================================================
// HOOK
// ============================================================

export function usePersistence(
  sections: SectionSchema[],
  layout: LayoutMode,
  tokens: DesignTokens,
  applicantName: string,
  contactLine: string,
) {
  const cloudTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const buildState = useCallback(
    (): PersistedState => ({
      sections,
      layout,
      tokens,
      applicantName,
      contactLine,
      savedAt: Date.now(),
    }),
    [sections, layout, tokens, applicantName, contactLine],
  );

  // Save to localStorage immediately on every change
  useEffect(() => {
    saveToLocal(buildState());
  }, [buildState]);

  // Debounced save to Supabase
  useEffect(() => {
    if (cloudTimerRef.current) clearTimeout(cloudTimerRef.current);
    cloudTimerRef.current = setTimeout(() => {
      saveToCloud(buildState());
    }, DEBOUNCE_MS);

    return () => {
      if (cloudTimerRef.current) clearTimeout(cloudTimerRef.current);
    };
  }, [buildState]);
}
