import { useState, useEffect } from 'react';

// ============================================================
// useSupabase — initializes and exposes the Supabase client
// ============================================================
// Wraps the existing @supabase/supabase-js client so React
// components can access auth, edge functions, and DB queries
// without reaching into window globals.
// ============================================================

const SUPABASE_URL = 'https://gwmpdgjvcjzndbloctla.supabase.co';
const SUPABASE_ANON_KEY = 'sb_publishable_Kor1B60TEAKofYE75aW7Ow_WL0cPOa8';

export interface SupabaseClient {
  auth: {
    getSession: () => Promise<{ data: { session: { access_token: string } | null } }>;
    onAuthStateChange: (cb: (event: string, session: any) => void) => { data: { subscription: { unsubscribe: () => void } } };
    signOut: () => Promise<void>;
  };
  functions: {
    invoke: (name: string, options: { body: any }) => Promise<{ data: any; error: any }>;
  };
  from: (table: string) => {
    select: (columns?: string) => any;
    insert: (rows: any) => any;
    update: (values: any) => any;
    upsert: (rows: any) => any;
    delete: () => any;
  };
}

let _client: SupabaseClient | null = null;

function getClient(): SupabaseClient | null {
  // Check if already cached
  if (_client) return _client;

  // Check if supabase-js is loaded via CDN (existing app pattern)
  if (window.supabase?.createClient) {
    _client = window.supabase.createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
    window.supabaseClient = _client; // keep backward compat with vanilla code
    return _client;
  }

  // If supabaseClient was already initialized by auth.js
  if (window.supabaseClient) {
    _client = window.supabaseClient;
    return _client;
  }

  return null;
}

export function useSupabase(): SupabaseClient | null {
  const [client, setClient] = useState<SupabaseClient | null>(getClient);

  useEffect(() => {
    if (client) return;

    // Poll briefly in case supabase-js loads async
    let attempts = 0;
    const interval = setInterval(() => {
      const c = getClient();
      if (c) {
        setClient(c);
        clearInterval(interval);
      }
      if (++attempts > 20) clearInterval(interval); // give up after 2s
    }, 100);

    return () => clearInterval(interval);
  }, [client]);

  return client;
}

// ---- Utility: call an edge function with auth ----

export async function invokeEdgeFunction(
  functionName: string,
  body: any,
  timeoutMs = 60000,
): Promise<any> {
  const client = getClient();

  if (client) {
    const result = await Promise.race([
      client.functions.invoke(functionName, { body }),
      new Promise<never>((_, reject) =>
        setTimeout(() => reject(new Error('Request timed out')), timeoutMs),
      ),
    ]);
    return result;
  }

  // Fallback: direct fetch (no SDK — client is null here)
  const token = SUPABASE_ANON_KEY;

  const resp = await fetch(`${SUPABASE_URL}/functions/v1/${functionName}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${token}`,
      apikey: SUPABASE_ANON_KEY,
    },
    body: JSON.stringify(body),
  });

  const data = await resp.json();
  if (!resp.ok) throw new Error(data.error || `Edge function failed (${resp.status})`);
  return { data, error: null };
}
