import React, { useCallback, useRef, useState } from 'react';
import type { SectionSchema, SectionType } from '../types/sections';
import type { SectionManagerAPI } from '../hooks/useSectionManager';

// ============================================================
// SECTION LIBRARY — Drag-and-drop section manager
// ============================================================
// Left-rail component that shows:
//   1. Current sections (draggable to reorder)
//   2. "Add Section" palette (standard + Enhancv blocks)
//   3. Layout toggle (1-col / 2-col)
// ============================================================

// ---- Block palette entries ----

interface PaletteEntry {
  type: SectionType;
  label: string;
  icon: string;
  category: 'standard' | 'enhancv';
}

const PALETTE: PaletteEntry[] = [
  { type: 'experience',    label: 'Experience',       icon: 'fa-briefcase',      category: 'standard' },
  { type: 'education',     label: 'Education',        icon: 'fa-graduation-cap', category: 'standard' },
  { type: 'skills',        label: 'Skills',           icon: 'fa-wrench',         category: 'standard' },
  { type: 'philosophy',    label: 'My Philosophy',    icon: 'fa-lightbulb',      category: 'enhancv' },
  { type: 'tech-stack',    label: 'Tech Stack Icons', icon: 'fa-layer-group',    category: 'enhancv' },
  { type: 'skills-cloud',  label: 'Soft Skills Cloud',icon: 'fa-cloud',          category: 'enhancv' },
  { type: 'strengths',     label: 'Strengths',        icon: 'fa-star',           category: 'enhancv' },
];

// ============================================================
// DRAGGABLE SECTION ITEM
// ============================================================

interface DraggableSectionProps {
  section: SectionSchema;
  index: number;
  onDragStart: (index: number) => void;
  onDragOver: (index: number) => void;
  onDragEnd: () => void;
  onRemove: (id: string) => void;
  onToggleVisibility: (id: string) => void;
  onColumnChange: (id: string, column: 'main' | 'sidebar') => void;
  isDragging: boolean;
  isDropTarget: boolean;
  layout: '1-col' | '2-col';
}

const DraggableSectionItem = React.memo(function DraggableSectionItem({
  section,
  index,
  onDragStart,
  onDragOver,
  onDragEnd,
  onRemove,
  onToggleVisibility,
  onColumnChange,
  isDragging,
  isDropTarget,
  layout,
}: DraggableSectionProps) {
  return (
    <div
      draggable
      onDragStart={() => onDragStart(index)}
      onDragOver={(e) => {
        e.preventDefault();
        onDragOver(index);
      }}
      onDragEnd={onDragEnd}
      className={`
        flex items-center gap-2 px-3 py-2 rounded-lg cursor-grab
        border transition-all text-sm
        ${isDragging ? 'opacity-40 scale-95' : ''}
        ${isDropTarget ? 'border-[var(--r-accent)] bg-[var(--r-accent-light)]' : 'border-gray-200 dark:border-gray-700'}
        ${!section.visible ? 'opacity-50' : ''}
        bg-white dark:bg-gray-800 hover:shadow-sm
      `}
    >
      {/* Drag handle */}
      <i className="fa-solid fa-grip-vertical text-gray-400 text-xs" />

      {/* Icon + title */}
      <i className={`fa-solid ${section.icon} text-[var(--r-accent)] text-xs`} />
      <span className="flex-1 truncate font-medium">{section.title}</span>

      {/* Column toggle (only in 2-col mode) */}
      {layout === '2-col' && (
        <button
          onClick={() =>
            onColumnChange(section.id, section.column === 'main' ? 'sidebar' : 'main')
          }
          className="text-[10px] px-1.5 py-0.5 rounded bg-gray-100 dark:bg-gray-700
                     text-gray-500 hover:text-[var(--r-accent)] transition-colors"
          title={`Move to ${section.column === 'main' ? 'sidebar' : 'main'}`}
        >
          {section.column === 'main' ? 'L' : 'R'}
        </button>
      )}

      {/* Visibility toggle */}
      <button
        onClick={() => onToggleVisibility(section.id)}
        className="text-gray-400 hover:text-[var(--r-accent)] transition-colors"
        title={section.visible ? 'Hide section' : 'Show section'}
      >
        <i className={`fa-solid ${section.visible ? 'fa-eye' : 'fa-eye-slash'} text-xs`} />
      </button>

      {/* Remove */}
      <button
        onClick={() => onRemove(section.id)}
        className="text-gray-400 hover:text-red-500 transition-colors"
        title="Remove section"
      >
        <i className="fa-solid fa-xmark text-xs" />
      </button>
    </div>
  );
});

// ============================================================
// SECTION LIBRARY (main export)
// ============================================================

interface SectionLibraryProps {
  manager: SectionManagerAPI;
}

export default function SectionLibrary({ manager }: SectionLibraryProps) {
  const {
    sections,
    layout,
    addSection,
    addCustomSection,
    removeSection,
    toggleVisibility,
    reorder,
    moveToColumn,
    setLayout,
  } = manager;

  // ---- Drag state ----
  const [dragIndex, setDragIndex] = useState<number | null>(null);
  const [dropIndex, setDropIndex] = useState<number | null>(null);
  const customTitleRef = useRef<HTMLInputElement>(null);

  const handleDragStart = useCallback((index: number) => setDragIndex(index), []);
  const handleDragOver = useCallback((index: number) => setDropIndex(index), []);

  const handleDragEnd = useCallback(() => {
    if (dragIndex !== null && dropIndex !== null && dragIndex !== dropIndex) {
      reorder(dragIndex, dropIndex);
    }
    setDragIndex(null);
    setDropIndex(null);
  }, [dragIndex, dropIndex, reorder]);

  const handleAddCustom = useCallback(() => {
    const title = customTitleRef.current?.value.trim();
    if (title) {
      addCustomSection(title);
      customTitleRef.current!.value = '';
    }
  }, [addCustomSection]);

  return (
    <aside className="section-library flex flex-col gap-4 w-full">
      {/* ---- Layout toggle ---- */}
      <div className="flex items-center gap-2">
        <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">Layout</span>
        <div className="flex rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700 ml-auto">
          <button
            onClick={() => setLayout('1-col')}
            className={`px-3 py-1.5 text-xs font-medium transition-colors ${
              layout === '1-col'
                ? 'bg-[var(--r-accent)] text-white'
                : 'bg-white dark:bg-gray-800 text-gray-600 hover:bg-gray-50'
            }`}
          >
            <i className="fa-solid fa-square mr-1" />
            1 Column
          </button>
          <button
            onClick={() => setLayout('2-col')}
            className={`px-3 py-1.5 text-xs font-medium transition-colors ${
              layout === '2-col'
                ? 'bg-[var(--r-accent)] text-white'
                : 'bg-white dark:bg-gray-800 text-gray-600 hover:bg-gray-50'
            }`}
          >
            <i className="fa-solid fa-columns mr-1" />
            2 Column
          </button>
        </div>
      </div>

      {/* ---- Current sections (draggable) ---- */}
      <div>
        <h3 className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-2">
          Sections
        </h3>
        <div className="flex flex-col gap-1.5">
          {sections.map((sec, i) => (
            <DraggableSectionItem
              key={sec.id}
              section={sec}
              index={i}
              onDragStart={handleDragStart}
              onDragOver={handleDragOver}
              onDragEnd={handleDragEnd}
              onRemove={removeSection}
              onToggleVisibility={toggleVisibility}
              onColumnChange={moveToColumn}
              isDragging={dragIndex === i}
              isDropTarget={dropIndex === i}
              layout={layout}
            />
          ))}
          {sections.length === 0 && (
            <p className="text-xs text-gray-400 italic py-4 text-center">
              No sections yet — add one below.
            </p>
          )}
        </div>
      </div>

      {/* ---- Add section palette ---- */}
      <div>
        <h3 className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-2">
          Add Block
        </h3>

        {/* Standard blocks */}
        <p className="text-[10px] text-gray-400 uppercase tracking-wider mb-1">Standard</p>
        <div className="grid grid-cols-2 gap-1.5 mb-3">
          {PALETTE.filter((p) => p.category === 'standard').map((entry) => (
            <button
              key={entry.type}
              onClick={() => addSection(entry.type)}
              className="flex items-center gap-1.5 px-2.5 py-2 rounded-lg border border-dashed
                         border-gray-300 dark:border-gray-600 text-xs text-gray-600 dark:text-gray-300
                         hover:border-[var(--r-accent)] hover:text-[var(--r-accent)]
                         transition-colors bg-white dark:bg-gray-800"
            >
              <i className={`fa-solid ${entry.icon}`} />
              {entry.label}
            </button>
          ))}
        </div>

        {/* Enhancv-style blocks */}
        <p className="text-[10px] text-gray-400 uppercase tracking-wider mb-1">Creative</p>
        <div className="grid grid-cols-2 gap-1.5 mb-3">
          {PALETTE.filter((p) => p.category === 'enhancv').map((entry) => (
            <button
              key={entry.type}
              onClick={() => addSection(entry.type)}
              className="flex items-center gap-1.5 px-2.5 py-2 rounded-lg border border-dashed
                         border-purple-300 dark:border-purple-700 text-xs text-purple-600 dark:text-purple-300
                         hover:border-purple-500 hover:text-purple-500
                         transition-colors bg-white dark:bg-gray-800"
            >
              <i className={`fa-solid ${entry.icon}`} />
              {entry.label}
            </button>
          ))}
        </div>

        {/* Custom block */}
        <p className="text-[10px] text-gray-400 uppercase tracking-wider mb-1">Custom</p>
        <div className="flex gap-1.5">
          <input
            ref={customTitleRef}
            type="text"
            placeholder="Section name..."
            className="flex-1 px-2.5 py-1.5 rounded-lg border border-gray-200 dark:border-gray-700
                       text-xs bg-white dark:bg-gray-800 focus:outline-none
                       focus:ring-1 focus:ring-[var(--r-accent)]"
            onKeyDown={(e) => e.key === 'Enter' && handleAddCustom()}
          />
          <button
            onClick={handleAddCustom}
            className="px-3 py-1.5 rounded-lg bg-[var(--r-accent)] text-white text-xs
                       font-medium hover:opacity-90 transition-opacity"
          >
            <i className="fa-solid fa-plus mr-1" />
            Add
          </button>
        </div>
      </div>
    </aside>
  );
}
