// ============================================================
// SECTION SCHEMA — The backbone of modular resume building
// ============================================================
// Every resume block (Experience, Education, Philosophy, etc.)
// is described by one SectionSchema. The editor reads the schema
// to render the correct inputs; the preview reads it to render
// semantic HTML. Adding a new block type = adding one schema def.
// ============================================================

/** Field types the editor understands */
export type FieldType =
  | 'text'          // Single-line input
  | 'textarea'      // Multi-line (plain)
  | 'bullet-text'   // Single textarea → rendered as icon-bulleted <ul>
  | 'date-range'    // Two date inputs (from / to)
  | 'icon-grid'     // Grid of selectable tech/tool icons
  | 'tag-cloud';    // Freeform tags rendered as a word-cloud

/** One field inside a section */
export interface FieldSchema {
  key: string;
  label: string;
  type: FieldType;
  placeholder?: string;
  value: string;              // Always stored as string; parsers hydrate
}

/** Semantic category for drag-and-drop grouping */
export type SectionCategory = 'standard' | 'enhancv' | 'custom';

/** The section types the system ships with */
export type SectionType =
  | 'experience'
  | 'education'
  | 'skills'
  | 'philosophy'
  | 'tech-stack'
  | 'skills-cloud'
  | 'strengths'
  | 'custom';

/** Which column in a 2-column layout */
export type ColumnSlot = 'main' | 'sidebar';

/** Full schema for one resume section */
export interface SectionSchema {
  id: string;
  type: SectionType;
  category: SectionCategory;
  title: string;
  icon: string;               // Font Awesome class, e.g. "fa-briefcase"
  column: ColumnSlot;
  order: number;
  visible: boolean;
  fields: FieldSchema[];
}

/** The entire resume document state */
export interface ResumeDocument {
  id: string;
  name: string;
  sections: SectionSchema[];
  layout: '1-col' | '2-col';
  createdAt: number;
  updatedAt: number;
}

// ============================================================
// DESIGN TOKEN TYPES
// ============================================================

export type TypographyMode = 'serif' | 'sans-serif';
export type DensityLevel = 'compact' | 'comfortable' | 'spacious';

export interface DesignTokens {
  typography: {
    mode: TypographyMode;
    serifStack: string;
    sansStack: string;
  };
  density: {
    level: DensityLevel;
    lineHeight: number;        // unitless multiplier
    sectionGap: number;        // px
    itemGap: number;           // px
    marginBottom: number;      // px — applied to paragraphs / list items
  };
  accent: {
    primary: string;           // hex, e.g. "#10b981"
  };
}

