import React, { useCallback, useMemo } from 'react';

// ============================================================
// SMART PARSER
// ============================================================
// Core UX contract: the *editor* shows a single <textarea> with
// plain-text bullets (lines starting with -, •, *, –, or just
// line breaks). The *preview* renders the same data as a styled,
// icon-bulleted <ul> using semantic HTML.
//
// This component exposes two sub-components:
//   <SmartParserEditor />  — the textarea (editor pane)
//   <SmartParserPreview /> — the rendered list (canvas pane)
//
// Both share the same `value` / `onChange` props so state lives
// in the parent section component.
// ============================================================

/** Regex that strips common bullet prefixes */
const BULLET_PREFIX = /^[\s]*[-•*–▸►◦‣⁃]\s*/;

/**
 * Parse a raw text block into an array of trimmed, non-empty lines.
 * Handles:
 *   - Lines starting with -, •, *, –, ►, etc.
 *   - Plain newline-separated lines (no prefix)
 *   - Mixed indentation
 */
export function parseTextToItems(raw: string): string[] {
  if (!raw) return [];
  return raw
    .split('\n')
    .map((line) => line.replace(BULLET_PREFIX, '').trim())
    .filter(Boolean);
}

// ============================================================
// EDITOR (textarea)
// ============================================================

interface SmartParserEditorProps {
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  label?: string;
  rows?: number;
}

export const SmartParserEditor = React.memo(function SmartParserEditor({
  value,
  onChange,
  placeholder = '- Type your bullets here\n- One per line',
  label,
  rows = 5,
}: SmartParserEditorProps) {
  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLTextAreaElement>) => onChange(e.target.value),
    [onChange],
  );

  return (
    <div className="smart-parser-editor">
      {label && (
        <label className="block text-xs font-medium text-gray-500 mb-1 uppercase tracking-wide">
          {label}
        </label>
      )}
      <textarea
        className="w-full rounded-lg border border-gray-200 bg-white px-3 py-2
                   text-sm leading-relaxed font-mono resize-y
                   focus:outline-none focus:ring-2 focus:ring-[var(--r-accent,#10b981)]
                   dark:bg-gray-900 dark:border-gray-700 dark:text-gray-100
                   transition-shadow"
        value={value}
        onChange={handleChange}
        placeholder={placeholder}
        rows={rows}
        spellCheck
      />
    </div>
  );
});

// ============================================================
// PREVIEW (rendered icon-bulleted list)
// ============================================================

interface SmartParserPreviewProps {
  value: string;
  /** Font Awesome icon class for the bullet marker, e.g. "fa-check" */
  bulletIcon?: string;
}

export const SmartParserPreview = React.memo(function SmartParserPreview({
  value,
  bulletIcon = 'fa-chevron-right',
}: SmartParserPreviewProps) {
  const items = useMemo(() => parseTextToItems(value), [value]);

  if (items.length === 0) return null;

  return (
    <ul
      role="list"
      style={{
        listStyle: 'none',
        padding: 0,
        margin: 0,
        lineHeight: 'var(--r-line-height, 1.5)',
      }}
    >
      {items.map((item, i) => (
        <li
          key={i}
          style={{
            display: 'flex',
            alignItems: 'flex-start',
            gap: '8px',
            marginBottom: 'var(--r-item-gap, 6px)',
          }}
        >
          {/* Icon bullet — decorative, hidden from screen readers */}
          <i
            className={`fa-solid ${bulletIcon}`}
            aria-hidden="true"
            style={{
              color: 'var(--r-accent, #10b981)',
              fontSize: '0.55em',
              marginTop: '0.55em',
              flexShrink: 0,
            }}
          />
          {/* Semantic <span> keeps ATS parsers happy */}
          <span>{item}</span>
        </li>
      ))}
    </ul>
  );
});

// ============================================================
// COMBINED (convenience wrapper)
// ============================================================

interface SmartParserProps {
  value: string;
  onChange: (value: string) => void;
  label?: string;
  placeholder?: string;
  bulletIcon?: string;
  rows?: number;
  /** 'editor' = textarea only, 'preview' = rendered list only */
  mode: 'editor' | 'preview';
}

export default function SmartParser({ mode, ...props }: SmartParserProps) {
  return mode === 'editor' ? (
    <SmartParserEditor
      value={props.value}
      onChange={props.onChange}
      label={props.label}
      placeholder={props.placeholder}
      rows={props.rows}
    />
  ) : (
    <SmartParserPreview value={props.value} bulletIcon={props.bulletIcon} />
  );
}
