import React, { useCallback } from 'react';
import { SmartParserEditor } from './SmartParser';
import type { SectionSchema } from '../types/sections';

// ============================================================
// SECTION EDITOR — renders the correct input fields for a
// single section based on its schema. bullet-text fields use
// the SmartParser textarea; other field types use native inputs.
// ============================================================

interface SectionEditorProps {
  section: SectionSchema;
  onFieldChange: (sectionId: string, fieldKey: string, value: string) => void;
  onTitleChange: (sectionId: string, title: string) => void;
}

export default React.memo(function SectionEditor({
  section,
  onFieldChange,
  onTitleChange,
}: SectionEditorProps) {
  const handleFieldChange = useCallback(
    (fieldKey: string) => (value: string) => {
      onFieldChange(section.id, fieldKey, value);
    },
    [section.id, onFieldChange],
  );

  return (
    <div className="section-editor rounded-xl border border-gray-200 dark:border-gray-700
                    bg-white dark:bg-gray-800 overflow-hidden">
      {/* ---- Section header ---- */}
      <div className="flex items-center gap-2 px-4 py-2.5 bg-gray-50 dark:bg-gray-750
                      border-b border-gray-200 dark:border-gray-700">
        <i className={`fa-solid ${section.icon} text-[var(--r-accent)] text-sm`} />
        <input
          type="text"
          value={section.title}
          onChange={(e) => onTitleChange(section.id, e.target.value)}
          className="flex-1 bg-transparent font-semibold text-sm text-gray-800
                     dark:text-gray-100 focus:outline-none border-none p-0"
        />
        <span className="text-[10px] text-gray-400 uppercase tracking-wider">
          {section.category}
        </span>
      </div>

      {/* ---- Fields ---- */}
      <div className="px-4 py-3 flex flex-col gap-3">
        {section.fields.map((field) => {
          switch (field.type) {
            // ---- Single text input ----
            case 'text':
              return (
                <div key={field.key}>
                  <label className="block text-xs font-medium text-gray-500 mb-1 uppercase tracking-wide">
                    {field.label}
                  </label>
                  <input
                    type="text"
                    value={field.value}
                    onChange={(e) => handleFieldChange(field.key)(e.target.value)}
                    placeholder={field.placeholder}
                    className="w-full rounded-lg border border-gray-200 dark:border-gray-700
                               bg-white dark:bg-gray-900 px-3 py-2 text-sm
                               focus:outline-none focus:ring-2 focus:ring-[var(--r-accent)]
                               transition-shadow"
                  />
                </div>
              );

            // ---- Date range (rendered as simple text for max flexibility) ----
            case 'date-range':
              return (
                <div key={field.key}>
                  <label className="block text-xs font-medium text-gray-500 mb-1 uppercase tracking-wide">
                    {field.label}
                  </label>
                  <input
                    type="text"
                    value={field.value}
                    onChange={(e) => handleFieldChange(field.key)(e.target.value)}
                    placeholder={field.placeholder || 'Jan 2022 – Present'}
                    className="w-full rounded-lg border border-gray-200 dark:border-gray-700
                               bg-white dark:bg-gray-900 px-3 py-2 text-sm
                               focus:outline-none focus:ring-2 focus:ring-[var(--r-accent)]
                               transition-shadow"
                  />
                </div>
              );

            // ---- Bullet text (Smart Parser textarea) ----
            case 'bullet-text':
              return (
                <SmartParserEditor
                  key={field.key}
                  value={field.value}
                  onChange={handleFieldChange(field.key)}
                  label={field.label}
                  placeholder={field.placeholder}
                  rows={5}
                />
              );

            // ---- Plain textarea ----
            case 'textarea':
              return (
                <div key={field.key}>
                  <label className="block text-xs font-medium text-gray-500 mb-1 uppercase tracking-wide">
                    {field.label}
                  </label>
                  <textarea
                    value={field.value}
                    onChange={(e) => handleFieldChange(field.key)(e.target.value)}
                    placeholder={field.placeholder}
                    rows={3}
                    className="w-full rounded-lg border border-gray-200 dark:border-gray-700
                               bg-white dark:bg-gray-900 px-3 py-2 text-sm resize-y
                               focus:outline-none focus:ring-2 focus:ring-[var(--r-accent)]
                               transition-shadow"
                  />
                </div>
              );

            // ---- Icon grid (comma-separated input) ----
            case 'icon-grid':
              return (
                <div key={field.key}>
                  <label className="block text-xs font-medium text-gray-500 mb-1 uppercase tracking-wide">
                    {field.label}
                  </label>
                  <input
                    type="text"
                    value={field.value}
                    onChange={(e) => handleFieldChange(field.key)(e.target.value)}
                    placeholder={field.placeholder || 'React, TypeScript, Node.js'}
                    className="w-full rounded-lg border border-gray-200 dark:border-gray-700
                               bg-white dark:bg-gray-900 px-3 py-2 text-sm
                               focus:outline-none focus:ring-2 focus:ring-[var(--r-accent)]
                               transition-shadow"
                  />
                  <p className="text-[10px] text-gray-400 mt-1">Separate with commas</p>
                </div>
              );

            // ---- Tag cloud (comma-separated input) ----
            case 'tag-cloud':
              return (
                <div key={field.key}>
                  <label className="block text-xs font-medium text-gray-500 mb-1 uppercase tracking-wide">
                    {field.label}
                  </label>
                  <input
                    type="text"
                    value={field.value}
                    onChange={(e) => handleFieldChange(field.key)(e.target.value)}
                    placeholder={field.placeholder || 'Leadership, Communication, Teamwork'}
                    className="w-full rounded-lg border border-gray-200 dark:border-gray-700
                               bg-white dark:bg-gray-900 px-3 py-2 text-sm
                               focus:outline-none focus:ring-2 focus:ring-[var(--r-accent)]
                               transition-shadow"
                  />
                  <p className="text-[10px] text-gray-400 mt-1">
                    Separate with commas. Earlier items appear larger.
                  </p>
                </div>
              );

            default:
              return null;
          }
        })}
      </div>
    </div>
  );
});
