import { useEffect, useRef } from 'react';
import type { SectionSchema } from '../types/sections';
import { SECTION_BLUEPRINTS } from '../types/sections';

// ============================================================
// useHydrateFromWizard — reads the tms_outputs payload that
// the vanilla JS wizard stores in sessionStorage after Gemini
// generates a tailored resume, and maps it into SectionSchema[]
// so the React builder opens pre-populated.
// ============================================================

interface WizardPayload {
  resumeHtml: string;
  applicantName: string;
  targetCompany: string;
  matchScore: number | null;
  missingKeywords: string[];
  companyPrimaryColor: string;
  resumeText: string;
  jobText: string;
}

/**
 * Parse the Gemini-generated resume HTML into section schemas.
 * The HTML follows a consistent pattern:
 *   <h2>Section Title</h2>
 *   <h3>Role / Degree</h3>
 *   <p>Company | Dates</p>
 *   <ul><li>Bullet</li>...</ul>
 */
function parseResumeHtml(html: string): SectionSchema[] {
  if (!html.trim()) return [];

  const parser = new DOMParser();
  const doc = parser.parseFromString(`<div>${html}</div>`, 'text/html');
  const container = doc.body.firstElementChild;
  if (!container) return [];

  const sections: SectionSchema[] = [];
  let currentH2: string | null = null;
  let currentH3: string | null = null;
  let currentMeta: string | null = null;
  let currentBullets: string[] = [];

  function flushSection() {
    if (!currentH2) return;

    const titleLower = currentH2.toLowerCase();
    const isEducation = titleLower.includes('education');
    const isSkills = titleLower.includes('skill') || titleLower.includes('technical');
    const isSummary = titleLower.includes('summary') || titleLower.includes('profile') || titleLower.includes('objective');

    if (isSummary) {
      const sec = SECTION_BLUEPRINTS.philosophy();
      sec.title = currentH2;
      sec.column = 'main';
      sec.fields[0].value = currentBullets.join('\n') || currentMeta || '';
      sec.order = sections.length;
      sections.push(sec);
    } else if (isSkills) {
      const sec = SECTION_BLUEPRINTS.skills();
      sec.title = currentH2;
      sec.fields[0].value = currentBullets.map(b => `- ${b}`).join('\n');
      sec.order = sections.length;
      sections.push(sec);
    } else if (isEducation) {
      const sec = SECTION_BLUEPRINTS.education();
      sec.title = currentH2;
      // Try to split meta into school | dates
      const parts = (currentMeta || '').split('|').map(s => s.trim());
      sec.fields[0].value = currentH3 || ''; // degree
      sec.fields[1].value = parts[0] || '';   // school
      sec.fields[2].value = parts[1] || '';   // dates
      sec.fields[3].value = currentBullets.map(b => `- ${b}`).join('\n');
      sec.order = sections.length;
      sections.push(sec);
    } else {
      // Experience or other
      const sec = SECTION_BLUEPRINTS.experience();
      sec.title = currentH2;
      const parts = (currentMeta || '').split('|').map(s => s.trim());
      sec.fields[0].value = currentH3 || ''; // job title
      sec.fields[1].value = parts[0] || '';   // company
      sec.fields[2].value = parts[1] || '';   // dates
      sec.fields[3].value = currentBullets.map(b => `- ${b}`).join('\n');
      sec.order = sections.length;
      sections.push(sec);
    }

    currentH3 = null;
    currentMeta = null;
    currentBullets = [];
  }

  const children = container.children;
  for (let i = 0; i < children.length; i++) {
    const el = children[i];
    const tag = el.tagName.toLowerCase();
    const text = (el.textContent || '').trim();

    if (tag === 'h2') {
      flushSection();
      currentH2 = text;
    } else if (tag === 'h3') {
      // If we already have bullets from a previous sub-entry, flush as a new section
      if (currentH3 && currentBullets.length > 0 && currentH2) {
        const savedTitle: string = currentH2;
        flushSection();
        // Keep the same h2 for the next sub-entry
        currentH2 = savedTitle;
      }
      currentH3 = text;
      currentMeta = null;
      currentBullets = [];
    } else if (tag === 'p') {
      currentMeta = text;
    } else if (tag === 'ul' || tag === 'ol') {
      const items = el.querySelectorAll('li');
      items.forEach(li => {
        const t = (li.textContent || '').trim();
        if (t) currentBullets.push(t);
      });
    }
  }

  // Flush last section
  flushSection();

  return sections;
}

/**
 * Fallback: parse raw resume text (from the original upload) into sections.
 * Less structured but ensures the builder is never empty.
 */
function parseResumeText(text: string): SectionSchema[] {
  if (!text.trim()) return [];

  // Simple heuristic: split on lines that look like section headers
  // (all caps, or followed by a line of dashes)
  const lines = text.split('\n');
  const sections: SectionSchema[] = [];
  let currentTitle = 'Experience';
  let currentContent: string[] = [];

  function flush() {
    if (currentContent.length === 0) return;
    const sec = SECTION_BLUEPRINTS.experience();
    sec.title = currentTitle;
    sec.fields[0].value = ''; // title
    sec.fields[1].value = ''; // company
    sec.fields[2].value = ''; // dates
    sec.fields[3].value = currentContent.map(l => l.startsWith('-') ? l : `- ${l}`).join('\n');
    sec.order = sections.length;
    sections.push(sec);
    currentContent = [];
  }

  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) continue;

    // Detect section headers: all caps and longer than 3 chars
    if (trimmed === trimmed.toUpperCase() && trimmed.length > 3 && !/^\d/.test(trimmed) && !trimmed.startsWith('-')) {
      flush();
      currentTitle = trimmed.charAt(0) + trimmed.slice(1).toLowerCase();
    } else {
      currentContent.push(trimmed);
    }
  }
  flush();

  return sections;
}

export function useHydrateFromWizard(
  loadSections: (sections: SectionSchema[]) => void,
  setApplicantName: (name: string) => void,
  setContactLine: (line: string) => void,
) {
  const hydrated = useRef(false);

  useEffect(() => {
    if (hydrated.current) return;
    hydrated.current = true;

    try {
      const raw = sessionStorage.getItem('tms_outputs');
      if (!raw) return;

      const payload: WizardPayload = JSON.parse(raw);

      // Try to parse the generated HTML first (most structured)
      let sections = parseResumeHtml(payload.resumeHtml);

      // Fallback to raw resume text if HTML parsing yielded nothing
      if (sections.length === 0 && payload.resumeText) {
        sections = parseResumeText(payload.resumeText);
      }

      if (sections.length === 0) return;

      loadSections(sections);

      if (payload.applicantName) {
        setApplicantName(payload.applicantName);
      }

      // Build a contact line from available data
      const contactParts = [payload.targetCompany ? `Target: ${payload.targetCompany}` : ''].filter(Boolean);
      if (contactParts.length > 0) {
        setContactLine(contactParts.join(' | '));
      }
    } catch (err) {
      console.warn('Failed to hydrate from wizard data:', err);
    }
  }, [loadSections, setApplicantName, setContactLine]);
}
