import React, { useState, useRef } from 'react';
import { DesignTokenProvider, useDesignTokens } from './context/DesignTokenContext';
import { useSectionManager } from './hooks/useSectionManager';
import { useSupabase } from './hooks/useSupabase';
import { usePersistence } from './hooks/usePersistence';
import { useHydrateFromWizard } from './hooks/useHydrateFromWizard';
import { SECTION_BLUEPRINTS } from './types/sections';
import SectionLibrary from './components/SectionLibrary';
import DesignControls from './components/DesignControls';
import LivePreview from './components/LivePreview';
import ExportButton from './components/ExportButton';
import AiTailorPanel from './components/AiTailorPanel';

/** Starter sections (used only if no wizard data is available) */
const STARTER_SECTIONS = [
  SECTION_BLUEPRINTS.experience(),
  SECTION_BLUEPRINTS.education(),
  SECTION_BLUEPRINTS.skills(),
];

function AppInner() {
  const manager = useSectionManager(STARTER_SECTIONS, '1-col');
  const { cssVars, tokens } = useDesignTokens();
  useSupabase();
  const [applicantName, setApplicantName] = useState('Your Name');
  const [contactLine, setContactLine] = useState(
    'city@email.com | (555) 123-4567 | linkedin.com/in/you',
  );
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const canvasRef = useRef<HTMLDivElement>(null);

  // Hydrate from the wizard's sessionStorage payload (tms_outputs)
  useHydrateFromWizard(manager.loadSections, setApplicantName, setContactLine);

  // Persist sections to Supabase
  usePersistence(manager.sections, manager.layout, tokens, applicantName, contactLine);

  return (
    <div
      className="app-shell h-screen flex flex-col"
      style={{
        ...cssVars as React.CSSProperties,
        fontFamily: "'Outfit', 'Helvetica Neue', Arial, sans-serif",
        background: 'var(--bg-color, #0d1117)',
        color: 'var(--text-primary, #e6edf3)',
      }}
    >
      {/* ---- Top bar ---- */}
      <header
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: '1rem',
          padding: '0.6rem 1.25rem',
          borderBottom: '1px dashed var(--panel-border, #1e2733)',
          background: 'var(--panel-bg, #161b22)',
        }}
      >
        <a
          href="app.html"
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: '0.5rem',
            color: 'var(--text-secondary, #8b949e)',
            textDecoration: 'none',
            fontSize: '0.85rem',
          }}
        >
          <i className="fa-solid fa-arrow-left" />
          Back
        </a>

        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <div
            style={{
              width: '28px',
              height: '28px',
              borderRadius: 'var(--brutal-radius, 4px)',
              background: 'var(--primary-color, #10b981)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '0.75rem',
              color: '#fff',
            }}
          >
            <i className="fa-solid fa-clipboard" />
          </div>
          <span style={{ fontWeight: 600, fontSize: '0.95rem' }}>Resume Editor</span>
        </div>

        <div style={{ flex: 1 }} />

        <input
          type="text"
          value={applicantName}
          onChange={(e) => setApplicantName(e.target.value)}
          placeholder="Your Name"
          style={{ width: '140px', fontSize: '0.8rem', padding: '0.35rem 0.6rem' }}
        />
        <input
          type="text"
          value={contactLine}
          onChange={(e) => setContactLine(e.target.value)}
          placeholder="Contact info..."
          style={{ width: '260px', fontSize: '0.8rem', padding: '0.35rem 0.6rem' }}
        />

        <ExportButton canvasRef={canvasRef} applicantName={applicantName} />
      </header>

      {/* ---- Body ---- */}
      <div style={{ display: 'flex', flex: 1, minHeight: 0 }}>
        {/* ======== SIDEBAR ======== */}
        {sidebarOpen && (
          <aside
            style={{
              width: '280px',
              flexShrink: 0,
              overflowY: 'auto',
              borderRight: '1px dashed var(--panel-border, #1e2733)',
              background: 'var(--panel-bg, #161b22)',
              padding: '1rem',
              display: 'flex',
              flexDirection: 'column',
              gap: '1.25rem',
            }}
          >
            <AiTailorPanel
              sections={manager.sections}
              onSectionsUpdate={manager.loadSections}
              applicantName={applicantName}
            />

            <div style={{ borderTop: '1px solid var(--panel-border, #1e2733)', paddingTop: '1rem' }}>
              <DesignControls />
            </div>

            <div style={{ borderTop: '1px solid var(--panel-border, #1e2733)', paddingTop: '1rem' }}>
              <SectionLibrary manager={manager} />
            </div>
          </aside>
        )}

        {/* Sidebar toggle */}
        <button
          onClick={() => setSidebarOpen((v) => !v)}
          style={{
            position: 'absolute',
            left: sidebarOpen ? '268px' : '0',
            top: '50%',
            transform: 'translateY(-50%)',
            zIndex: 10,
            width: '24px',
            height: '48px',
            borderRadius: '0 var(--brutal-radius, 4px) var(--brutal-radius, 4px) 0',
            background: 'var(--panel-bg, #161b22)',
            border: '1px dashed var(--panel-border, #1e2733)',
            borderLeft: 'none',
            color: 'var(--text-secondary, #8b949e)',
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '0.65rem',
          }}
        >
          <i className={`fa-solid ${sidebarOpen ? 'fa-chevron-left' : 'fa-chevron-right'}`} />
        </button>

        {/* ======== MAIN AREA ======== */}
        <main style={{ flex: 1, minWidth: 0, padding: '1rem' }}>
          <LivePreview
            manager={manager}
            applicantName={applicantName}
            contactLine={contactLine}
            canvasRef={canvasRef}
          />
        </main>
      </div>
    </div>
  );
}

export default function App() {
  return (
    <DesignTokenProvider>
      <AppInner />
    </DesignTokenProvider>
  );
}
