import { useState, useCallback } from 'react';
import { invokeEdgeFunction } from '../hooks/useSupabase';
import type { SectionSchema, FieldSchema } from '../types/sections';
import { SECTION_BLUEPRINTS } from '../types/sections';

// ============================================================
// AI TAILOR PANEL — Gemini-powered resume tailoring
// ============================================================
// Paste a job description → Gemini rewrites your section
// bullets to match the JD's keywords and tone, then returns
// updated SectionSchema data that replaces the current sections.
// ============================================================

interface AiTailorPanelProps {
  sections: SectionSchema[];
  onSectionsUpdate: (sections: SectionSchema[]) => void;
  applicantName: string;
}

type TailorStatus = 'idle' | 'loading' | 'done' | 'error';

/** Serialize sections into plain text for the AI prompt */
function sectionsToText(sections: SectionSchema[]): string {
  return sections
    .filter((s) => s.visible)
    .map((s) => {
      const heading = s.title;
      const body = s.fields
        .map((f) => `${f.label}: ${f.value}`)
        .filter((line) => line.length > 3)
        .join('\n');
      return `## ${heading}\n${body}`;
    })
    .join('\n\n');
}

const TAILOR_SYSTEM_PROMPT = `You are an elite ATS Resume Writer. You will receive:
1. A candidate's resume data (structured by section)
2. A target job description

Your job: REWRITE the resume bullets to maximize ATS match for the job.

Rules:
- Every bullet must start with a strong action verb.
- Weave in relevant keywords from the job description naturally.
- Preserve all real metrics/numbers — never fabricate data.
- Keep the same section structure and field keys.
- Return ONLY valid JSON — an array of section objects matching this schema:

[
  {
    "type": "experience",
    "title": "Experience",
    "fields": {
      "title": "Job Title",
      "company": "Company",
      "dates": "Start – End",
      "bullets": "- Bullet 1\\n- Bullet 2"
    }
  }
]

The "fields" object must use the same keys as the input (title, company, dates, bullets, degree, school, details, skills, quote, icons, tags, strengths, content).
Return every section from the input, even if unchanged.`;

export default function AiTailorPanel({
  sections,
  onSectionsUpdate,
  applicantName,
}: AiTailorPanelProps) {
  const [jobDesc, setJobDesc] = useState('');
  const [status, setStatus] = useState<TailorStatus>('idle');
  const [error, setError] = useState<string | null>(null);

  const handleTailor = useCallback(async () => {
    if (!jobDesc.trim()) return;
    if (sections.length === 0) {
      setError('Add resume sections before tailoring.');
      setStatus('error');
      return;
    }

    setStatus('loading');
    setError(null);

    try {
      const resumeText = sectionsToText(sections);

      const { data, error: fnError } = await invokeEdgeFunction(
        'gemini-proxy',
        {
          model: 'gemini-3-flash-preview',
          systemInstruction: { parts: [{ text: TAILOR_SYSTEM_PROMPT }] },
          contents: [
            {
              parts: [
                {
                  text: `Candidate Name: ${applicantName}\n\nResume Data:\n${resumeText}\n\nTarget Job Description:\n${jobDesc}`,
                },
              ],
            },
          ],
          generationConfig: { temperature: 0.5 },
        },
        90000,
      );

      if (fnError) throw new Error(fnError.message || 'AI tailoring failed');

      const responseText =
        data?.candidates?.[0]?.content?.parts?.[0]?.text || '';

      // Strip markdown fences
      const jsonStr = responseText
        .replace(/^```(?:json)?\s*/m, '')
        .replace(/```\s*$/m, '')
        .trim();

      let parsed: any[];
      try {
        parsed = JSON.parse(jsonStr);
      } catch {
        throw new Error('AI returned invalid data. Please try again.');
      }

      if (!Array.isArray(parsed)) throw new Error('Expected array of sections');

      // Map the AI response back into SectionSchema objects
      const updated: SectionSchema[] = parsed.map((item, i) => {
        // Find the matching original section by type + order
        const original = sections.find(
          (s) => s.type === item.type && s.title === item.title,
        ) || sections[i];

        if (!original) {
          // AI added a section not in the original — create from blueprint
          const blueprintFn = (SECTION_BLUEPRINTS as Record<string, (() => SectionSchema) | undefined>)[item.type];
          const bp = blueprintFn ? blueprintFn() : null;
          if (!bp) return null;
          // fill fields from AI
          for (const [key, val] of Object.entries(item.fields || {})) {
            const field = bp.fields.find((f: FieldSchema) => f.key === key);
            if (field) field.value = val as string;
          }
          bp.order = i;
          return bp;
        }

        // Update field values from AI response
        const updatedFields = original.fields.map((f) => ({
          ...f,
          value: (item.fields && item.fields[f.key]) ?? f.value,
        }));

        return {
          ...original,
          title: item.title || original.title,
          fields: updatedFields,
          order: i,
        };
      }).filter(Boolean) as SectionSchema[];

      onSectionsUpdate(updated);
      setStatus('done');
    } catch (err: any) {
      setError(err.message || 'Tailoring failed');
      setStatus('error');
    }
  }, [jobDesc, sections, applicantName, onSectionsUpdate]);

  return (
    <div className="ai-tailor-panel rounded-xl border border-gray-200 dark:border-gray-700
                    bg-white dark:bg-gray-800 p-4">
      <div className="flex items-center gap-2 mb-3">
        <i className="fa-solid fa-wand-magic-sparkles text-purple-500" />
        <h3 className="text-sm font-semibold text-gray-800 dark:text-gray-100">
          AI Tailor
        </h3>
      </div>

      <p className="text-xs text-gray-500 mb-3">
        Paste a job description and AI will rewrite your bullets to
        maximize ATS keyword match.
      </p>

      <textarea
        value={jobDesc}
        onChange={(e) => setJobDesc(e.target.value)}
        placeholder="Paste the target job description here..."
        rows={4}
        className="w-full rounded-lg border border-gray-200 dark:border-gray-700
                   bg-white dark:bg-gray-900 px-3 py-2 text-xs resize-y
                   focus:outline-none focus:ring-2 focus:ring-purple-500
                   transition-shadow mb-2"
      />

      <button
        onClick={handleTailor}
        disabled={!jobDesc.trim() || status === 'loading'}
        className="w-full py-2.5 rounded-lg bg-purple-600 text-white text-sm font-medium
                   hover:bg-purple-700 disabled:opacity-50 disabled:cursor-not-allowed
                   transition-colors flex items-center justify-center gap-2"
      >
        {status === 'loading' ? (
          <>
            <i className="fa-solid fa-spinner fa-spin text-xs" />
            Tailoring with AI...
          </>
        ) : (
          <>
            <i className="fa-solid fa-bullseye text-xs" />
            Tailor Resume to Job
          </>
        )}
      </button>

      {status === 'done' && (
        <p className="mt-2 text-xs text-green-600 flex items-center gap-1">
          <i className="fa-solid fa-check-circle" />
          Sections updated! Review the changes in the editor.
        </p>
      )}

      {status === 'error' && error && (
        <p className="mt-2 text-xs text-red-500 flex items-start gap-1">
          <i className="fa-solid fa-triangle-exclamation mt-0.5" />
          {error}
        </p>
      )}
    </div>
  );
}
