import { useDesignTokens } from '../context/DesignTokenContext';
import type { TypographyMode, DensityLevel } from '../types/sections';

// ============================================================
// DESIGN CONTROLS — Global token editor panel
// ============================================================
// Compact sidebar controls for:
//   1. Typography toggle (Serif / Sans-Serif)
//   2. Density slider (Compact / Comfortable / Spacious)
//   3. Accent color picker
// Changes propagate instantly via CSS custom properties.
// ============================================================

const ACCENT_PRESETS = [
  { hex: '#10b981', label: 'Emerald' },
  { hex: '#3b82f6', label: 'Blue' },
  { hex: '#8b5cf6', label: 'Violet' },
  { hex: '#ef4444', label: 'Red' },
  { hex: '#f59e0b', label: 'Amber' },
  { hex: '#06b6d4', label: 'Cyan' },
  { hex: '#111827', label: 'Black' },
  { hex: '#c9a84c', label: 'Gold' },
];

const DENSITY_OPTIONS: { value: DensityLevel; label: string; desc: string }[] = [
  { value: 'compact',     label: 'Compact',     desc: 'Tight spacing — fits more content' },
  { value: 'comfortable', label: 'Comfortable', desc: 'Balanced — good default' },
  { value: 'spacious',    label: 'Spacious',    desc: 'Open spacing — easier to scan' },
];

export default function DesignControls() {
  const { tokens, setTypography, setDensity, setAccent, resetTokens } = useDesignTokens();

  return (
    <div className="design-controls flex flex-col gap-5">
      <h3 className="text-xs font-semibold text-gray-500 uppercase tracking-wide">
        Design Tokens
      </h3>

      {/* ---- Typography ---- */}
      <div>
        <label className="block text-xs font-medium text-gray-500 mb-2 uppercase tracking-wide">
          Typography
        </label>
        <div className="flex rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700">
          {(['sans-serif', 'serif'] as TypographyMode[]).map((mode) => (
            <button
              key={mode}
              onClick={() => setTypography(mode)}
              className={`flex-1 px-3 py-2 text-xs font-medium transition-colors ${
                tokens.typography.mode === mode
                  ? 'bg-[var(--r-accent)] text-white'
                  : 'bg-white dark:bg-gray-800 text-gray-600 hover:bg-gray-50'
              }`}
              style={
                mode === 'serif'
                  ? { fontFamily: tokens.typography.serifStack }
                  : { fontFamily: tokens.typography.sansStack }
              }
            >
              {mode === 'serif' ? 'Serif' : 'Sans-Serif'}
            </button>
          ))}
        </div>
        <p className="text-[10px] text-gray-400 mt-1">
          Both stacks are ATS-optimized with web-safe fallbacks.
        </p>
      </div>

      {/* ---- Density ---- */}
      <div>
        <label className="block text-xs font-medium text-gray-500 mb-2 uppercase tracking-wide">
          Layout Spacing
        </label>
        <div className="flex flex-col gap-1.5">
          {DENSITY_OPTIONS.map((opt) => (
            <button
              key={opt.value}
              onClick={() => setDensity(opt.value)}
              className={`flex items-center gap-2 px-3 py-2 rounded-lg border text-left
                         text-xs transition-all ${
                           tokens.density.level === opt.value
                             ? 'border-[var(--r-accent)] bg-[var(--r-accent-light)] text-[var(--r-accent)] font-semibold'
                             : 'border-gray-200 dark:border-gray-700 text-gray-600 hover:border-gray-300'
                         }`}
            >
              <span className="flex-1">{opt.label}</span>
              <span className="text-[10px] text-gray-400 font-normal">{opt.desc}</span>
            </button>
          ))}
        </div>
      </div>

      {/* ---- Accent Color ---- */}
      <div>
        <label className="block text-xs font-medium text-gray-500 mb-2 uppercase tracking-wide">
          Accent Color
        </label>
        {/* Preset swatches */}
        <div className="flex flex-wrap gap-2 mb-2">
          {ACCENT_PRESETS.map((preset) => (
            <button
              key={preset.hex}
              onClick={() => setAccent(preset.hex)}
              className={`w-7 h-7 rounded-full border-2 transition-transform hover:scale-110 ${
                tokens.accent.primary === preset.hex
                  ? 'border-gray-800 dark:border-white scale-110 ring-2 ring-offset-1 ring-gray-300'
                  : 'border-transparent'
              }`}
              style={{ backgroundColor: preset.hex }}
              title={preset.label}
            />
          ))}
        </div>
        {/* Custom hex input */}
        <div className="flex items-center gap-2">
          <input
            type="color"
            value={tokens.accent.primary}
            onChange={(e) => setAccent(e.target.value)}
            className="w-8 h-8 rounded cursor-pointer border-0 p-0"
          />
          <input
            type="text"
            value={tokens.accent.primary}
            onChange={(e) => {
              const v = e.target.value;
              if (/^#[0-9a-fA-F]{6}$/.test(v)) setAccent(v);
            }}
            maxLength={7}
            className="w-24 px-2 py-1.5 rounded border border-gray-200 dark:border-gray-700
                       bg-white dark:bg-gray-900 text-xs font-mono
                       focus:outline-none focus:ring-1 focus:ring-[var(--r-accent)]"
          />
        </div>
      </div>

      {/* ---- Reset ---- */}
      <button
        onClick={resetTokens}
        className="mt-2 text-xs text-gray-400 hover:text-red-500 transition-colors self-start"
      >
        <i className="fa-solid fa-rotate-left mr-1" />
        Reset to defaults
      </button>
    </div>
  );
}
