import React from 'react';
import SectionEditor from './SectionEditor';
import ResumeCanvas from './ResumeCanvas';
import type { SectionManagerAPI } from '../hooks/useSectionManager';

// ============================================================
// LIVE PREVIEW — Side-by-side Editor | Canvas
// ============================================================
// Left pane: scrollable list of SectionEditors (one per section)
// Right pane: CSS-scaled ResumeCanvas that mirrors final PDF
//
// Performance: Each SectionEditor is React.memo'd and only
// re-renders when its specific section data changes. The canvas
// reads design tokens via CSS variables (no per-component
// re-render on token changes). Typing in the editor triggers
// a state update → React reconciles only the changed field →
// canvas re-renders only the affected SectionRenderer.
// ============================================================

interface LivePreviewProps {
  manager: SectionManagerAPI;
  applicantName?: string;
  contactLine?: string;
  /** Forwarded ref so the export button can access the canvas DOM */
  canvasRef?: React.RefObject<HTMLDivElement | null>;
}

export default function LivePreview({
  manager,
  applicantName,
  contactLine,
  canvasRef,
}: LivePreviewProps) {
  const { sections, layout, updateField, updateTitle } = manager;

  return (
    <div className="live-preview flex gap-6 h-full min-h-0">
      {/* ======== EDITOR PANE ======== */}
      <div
        className="editor-pane flex-1 overflow-y-auto pr-2
                   flex flex-col gap-4 min-w-0
                   scrollbar-thin scrollbar-thumb-gray-300 dark:scrollbar-thumb-gray-600"
      >
        {sections.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-gray-400">
            <i className="fa-solid fa-layer-group text-4xl mb-3 opacity-40" />
            <p className="text-sm">Add sections from the sidebar to get started.</p>
          </div>
        ) : (
          sections.map((section) => (
            <SectionEditor
              key={section.id}
              section={section}
              onFieldChange={updateField}
              onTitleChange={updateTitle}
            />
          ))
        )}
      </div>

      {/* ======== CANVAS PANE ======== */}
      <div
        ref={canvasRef}
        className="canvas-pane flex-1 overflow-y-auto min-w-0
                   bg-gray-100 dark:bg-gray-900 rounded-xl p-4
                   scrollbar-thin scrollbar-thumb-gray-300 dark:scrollbar-thumb-gray-600"
      >
        <ResumeCanvas
          sections={sections}
          layout={layout}
          applicantName={applicantName}
          contactLine={contactLine}
        />
      </div>
    </div>
  );
}
